// toolbar.js
import { DraggableNode } from './draggableNode';

const nodes = [
  { type: 'customInput', label: 'Input', color: '#22d3ee', icon: '⬇' },
  { type: 'customOutput', label: 'Output', color: '#34d399', icon: '⬆' },
  { type: 'llm', label: 'LLM', color: '#a78bfa', icon: '🧠' },
  { type: 'text', label: 'Text', color: '#f59e0b', icon: '✏️' },
  { type: 'api', label: 'API Call', color: '#38bdf8', icon: '🌐' },
  { type: 'filter', label: 'Filter', color: '#fb7185', icon: '🔍' },
  { type: 'transform', label: 'Transform', color: '#c084fc', icon: '⚙️' },
  { type: 'merge', label: 'Merge', color: '#4ade80', icon: '🔀' },
  { type: 'note', label: 'Note', color: '#fbbf24', icon: '📝' },
];

export const PipelineToolbar = () => {
  return (
    <div
      style={{
        padding: '12px 16px',
        background: 'linear-gradient(180deg, #0f1420 0%, #111827 100%)',
        borderBottom: '1px solid rgba(255,255,255,0.06)',
        display: 'flex',
        alignItems: 'center',
        gap: '12px',
      }}
    >
      {/* Logo / title */}
      <div style={{ marginRight: 8, flexShrink: 0 }}>
        <span
          style={{
            fontSize: 13,
            fontWeight: 800,
            letterSpacing: '0.12em',
            textTransform: 'uppercase',
            background: 'linear-gradient(90deg, #a78bfa, #38bdf8)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            fontFamily: "'Inter','Segoe UI',sans-serif",
          }}
        >
          VectorShift
        </span>
        <div style={{ fontSize: 9, color: 'rgba(255,255,255,0.3)', letterSpacing: '0.1em', marginTop: 1, fontFamily: 'sans-serif' }}>
          PIPELINE BUILDER
        </div>
      </div>

      <div style={{ width: 1, height: 36, background: 'rgba(255,255,255,0.08)', flexShrink: 0 }} />

      {/* Node palette */}
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px', alignItems: 'center' }}>
        {nodes.map((n) => (
          <DraggableNode key={n.type} type={n.type} label={n.label} color={n.color} icon={n.icon} />
        ))}
      </div>
    </div>
  );
};
